settings.custom_liquid:
{% liquid
  assign product_resource = closest.product
  if request.visual_preview_mode and product_resource == blank
    assign product_resource = collections.all.products.first
  endif
-%}

{% unless product_resource == blank %}
  {%- assign color_option = product_resource.options_with_values | where: 'name', 'Color' | first -%}
  {%- if color_option == blank -%}
    {%- assign color_option = product_resource.options_with_values | where: 'name', 'Colour' | first -%}
  {%- endif -%}

  {% if color_option and color_option.values.size > 1 %}
    <style>
    @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600&display=swap');

    .tsukie-block-colorpicker{
      margin-top:16px;
      margin-bottom:16px;
    }
    .tsukie-block-color-label{
      display: none;

      display: none;

      font-size:11px;
      letter-spacing:2px;
      text-transform:uppercase;
      color:#1e2a38;
      margin:0 0 12px;
      font-weight:500;
      font-family:'Montserrat',sans-serif;
    }
    .tsukie-block-color-label span{
      color:#6b6b6b;
      font-weight:400;
      margin-left:4px;
    }
    .tsukie-block-swatches{
      display:flex;
      gap:6px;
      align-items:center;
      flex-wrap:wrap;
    }
    .tsukie-block-swatch{
      width:18px;
      height:18px;
      border-radius:50%;
      border:1px solid #c9c9c9;
      cursor:pointer;
      flex-shrink:0;
      box-sizing:border-box;
      background-color:var(--swatch-color);
      padding:0;
      transition:all 0.2s ease;
      position:relative;
    }
    .tsukie-block-swatch:hover{
      transform:scale(1.1);
    }
    .tsukie-block-swatch.active{
      border:2px solid #1e2a38;
    }
    </style>

    <div class="tsukie-block-colorpicker">
      <p class="tsukie-block-color-label">
        COLOR:<span id="tsukie-block-selected-{{ section.id }}">{{ product_resource.selected_or_first_available_variant.option1 }}</span>
      </p>

      <div class="tsukie-block-swatches">
        {% for value in color_option.values %}
          {%- liquid
            assign variant_for_color = blank
            assign color_downcase = value | downcase

            for variant in product_resource.variants
              if variant.option1 == value or variant.option2 == value or variant.option3 == value
                assign variant_for_color = variant
                break
              endif
            endfor

            assign bg_color = color_downcase | replace: ' ', ''
            case color_downcase
              when 'navy blue' 
                assign bg_color = '#001f3f'
              when 'off white' 
                assign bg_color = '#f8f8f8'
              when 'beige' 
                assign bg_color = '#f5f1ea'
              when 'black' 
                assign bg_color = '#000000'
              when 'white' 
                assign bg_color = '#ffffff'
            endcase
          -%}

          <button 
            class="tsukie-block-swatch {% if product_resource.selected_or_first_available_variant.id == variant_for_color.id %}active{% endif %}"
            data-variant-id="{{ variant_for_color.id }}"
            data-color-name="{{ value }}"
            type="button"
            style="--swatch-color: {{ bg_color }}"
            onclick="tsukieBlockColorSelect{{ section.id }}(this)"
            title="{{ value }}"
          >
          </button>
        {% endfor %}
      </div>
    </div>

    <script>
    function tsukieBlockColorSelect{{ section.id }}(btn){
      document.querySelectorAll('#shopify-section-{{ section.id }} .tsukie-block-swatch').forEach(s => s.classList.remove('active'));
      btn.classList.add('active');

      document.getElementById('tsukie-block-selected-{{ section.id }}').textContent = btn.dataset.colorName;

      let variantInput = document.querySelector('form[action*="/cart/add"] input[name="id"]');
      if(variantInput && btn.dataset.variantId){
        variantInput.value = btn.dataset.variantId;
        variantInput.dispatchEvent(new Event('change', {bubbles: true}));
      }
    }
    </script>
  {% endif %}
{% endunless %}
